import requests

KONG_ADMIN_URL = 'http://localhost:8001'  # Change this to your Kong Admin URL

def create_service(service_name, url):
    payload = {
        'name': service_name,
        'url': url
    }
    response = requests.post(f'{KONG_ADMIN_URL}/services', json=payload)
    return response.json()

def create_route(service_name, paths):
    payload = {
        'paths': paths,
        'service': {
            'name': service_name
        }
    }
    response = requests.post(f'{KONG_ADMIN_URL}/routes', json=payload)
    return response.json()

def create_upstream(upstream_name):
    payload = {
        'name': upstream_name
    }
    response = requests.post(f'{KONG_ADMIN_URL}/upstreams', json=payload)
    return response.json()

def create_target(upstream_name, target_url, weight=100):
    payload = {
        'target': target_url,
        'weight': weight
    }
    response = requests.post(f'{KONG_ADMIN_URL}/upstreams/{upstream_name}/targets', json=payload)
    return response.json()

# Example usage
